sql:
SELECT COUNT(*) 
  FROM patients 
  WHERE country_id = (SELECT country_id FROM countries WHERE country_name = 'Pakistan');

SELECT DISTINCT sp.patient_id, sp.study_id, sp.enrollment_date 
FROM study_participants sp 
WHERE sp.study_id = '2' AND sp.patient_id != 0;

SELECT agecat_name
FROM age_categories
WHERE agecat_id = (SELECT agecat_id FROM patients WHERE patient_id = 1);

SELECT COUNT(*) AS patient_count
FROM patients
WHERE syntype_id = (SELECT syntype_id FROM syntypes WHERE syntype_name = 'LSIL');

SELECT AVG(
  strftime('%Y', 'now') - strftime('%Y', p.date_of_birth)
) AS average_age
FROM patients p
JOIN diagnostics d ON p.patient_id = d.patient_id
WHERE d.method_id = 0;
